// ============================================================
// CONSOLIDATE ALL DATA
// Merges all parallel branch outputs into one clean object
// for the AI Interview Coach agent.
//
// Inputs (some optional — node runs regardless of which branches fired):
//   - Form Trigger          → always available (email, LinkedIn URLs)
//   - Run: Scrape User LinkedIn    → always ran
//   - Run: Scrape Interviewer LinkedIn → only if Interviewer URL was provided
//   - Run: Scrape Company LinkedIn     → only if Company URL was provided
//   - Extract from File     → only if a CV was uploaded
// ============================================================

const formData = $('Form Trigger').first().json;

// ── Helper: safely pull all items from a node, returns [] if it never ran ──
function safeGetAll(nodeName) {
  try {
    const items = $(nodeName).all();
    return (items && items.length > 0) ? items.map(i => i.json) : [];
  } catch (e) {
    return [];
  }
}

// ── Helper: safely get a single text value from a node ──
function safeGetText(nodeName, textKey = 'text') {
  try {
    const items = $(nodeName).all();
    if (!items || items.length === 0) return null;
    return items[0].json[textKey] || null;
  } catch (e) {
    return null;
  }
}

// ── 1. User LinkedIn profile (always expected) ──
const userProfileData = safeGetAll('Run: Scrape User LinkedIn');
const userProfile = userProfileData.length > 0
  ? JSON.stringify(userProfileData, null, 2)
  : 'Not available — scrape may have failed.';

// ── 2. Interviewer LinkedIn profile (optional) ──
const interviewerProfileData = safeGetAll('Run: Scrape Interviewer LinkedIn');
const interviewerProfile = interviewerProfileData.length > 0
  ? JSON.stringify(interviewerProfileData, null, 2)
  : 'Not provided — no interviewer LinkedIn URL was submitted.';

// ── 3. Company LinkedIn profile (optional) ──
const companyProfileData = safeGetAll('Run: Scrape Company LinkedIn');
const companyProfile = companyProfileData.length > 0
  ? JSON.stringify(companyProfileData, null, 2)
  : 'Not provided — no company LinkedIn URL was submitted.';

// ── 4. CV text from uploaded PDF (optional) ──
// The "Extract from File" node outputs a `.text` field containing the raw PDF text.
const cvText = safeGetText('Extract from File', 'text')
  || 'Not provided — no CV was uploaded.';

// ── 5. Metadata from the form ──
const email = formData.Your_Email || '';
const userLinkedIn  = formData.User_LinkedIn || '';
const interviewerLinkedIn = formData.Interviewer_LinkedIn || '';
const companyLinkedIn = formData.Company_LinkedIn || '';

// ── Build the consolidated output ──
return [{
  json: {
    // Recipient for the final email
    email,

    // Raw form inputs (useful for the AI to reference URLs directly)
    submittedUrls: {
      user: userLinkedIn,
      interviewer: interviewerLinkedIn || null,
      company: companyLinkedIn || null,
    },

    // Scraped profile data (JSON strings — AI can read structured JSON naturally)
    userProfile,
    interviewerProfile,
    companyProfile,

    // Plain-text CV content
    cvText,

    // Availability flags — lets the AI know what data it actually has
    dataAvailability: {
      hasUserProfile:       userProfileData.length > 0,
      hasInterviewerProfile: interviewerProfileData.length > 0,
      hasCompanyProfile:    companyProfileData.length > 0,
      hasCv:                cvText !== 'Not provided — no CV was uploaded.',
    },
  }
}];

